final class Image {

    /**
     * Get random image url
     * 
     * 获取随机图片 URL
     * 
     * Custom Filter: g3_filter_image_sources
     * 
     * @param int $width  Image width
     * @param int $height Image height
     * @param string $source Image source
     * @return string
     */
    public static function randomImage(int $width = 1080, int $height = 720, string $source = 'picsum'): string
    {
        $url     = '';
        $sources = [
            'local'  => \plugins_url('public/img/unsplash/' . rand(1, 65) . '.jpg', dirname(__FILE__, 4)),
            // picsum.photos 最多 1084 张图片
            'picsum' => 'https://picsum.photos/%d/%d.webp'
        ];

        /**
         * Custom Filter: g3_filter_image_sources
         */
        $sources = \apply_filters('g3_filter_image_sources', $sources);

        switch ($source) {
            case 'local':
                $url = $sources[$source];
                break;
            case 'picsum':
            default:
                $url = \sprintf($sources[$source], $width, $height);
                break;
        }

        return $url;
    }

